                } catch (Exception e) {
                    throw DbException.convert(e);
                }
                return returnValue;
            } finally {
                session.setLastIdentity(identity);
                session.setAutoCommit(old);
                if (defaultConnection) {
                    Driver.setDefaultConnection(null);
                }
            }
        }

